"""Payment gateway abstraction layer."""
from abc import ABC, abstractmethod
from dataclasses import dataclass
from decimal import Decimal
import stripe
import braintree


@dataclass
class ChargeResult:
    transaction_id: str
    gateway: str
    status: str
    raw_response: dict | None = None


class PaymentGateway(ABC):
    @abstractmethod
    def charge(self, amount_cents: int, currency: str, token: str) -> ChargeResult:
        ...


class StripeGateway(PaymentGateway):
    SUPPORTED_CURRENCIES = frozenset({'USD', 'CAD', 'GBP', 'EUR', 'AUD'})

    def charge(self, amount_cents: int, currency: str, token: str) -> ChargeResult:
        charge = stripe.Charge.create(
            amount=amount_cents,
            currency=currency.lower(),
            source=token,
        )
        return ChargeResult(
            transaction_id=charge.id,
            gateway='stripe',
            status='completed',
        )


class BraintreeGateway(PaymentGateway):
    def charge(self, amount_cents: int, currency: str, token: str) -> ChargeResult:
        result = braintree.Transaction.sale({
            'amount': str(Decimal(amount_cents) / 100),
            'payment_method_nonce': token,
        })
        if not result.is_success:
            raise PaymentError(f'Braintree declined: {result.message}')
        return ChargeResult(
            transaction_id=result.transaction.id,
            gateway='braintree',
            status='completed',
        )


def get_gateway(currency: str) -> PaymentGateway:
    if currency in StripeGateway.SUPPORTED_CURRENCIES:
        return StripeGateway()
    return BraintreeGateway()


class PaymentError(Exception):
    pass

